const body = $input.first().json.body || $input.first().json;
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!body.tenantId || !uuidRegex.test(body.tenantId)) {
  throw new Error('Invalid or missing tenantId');
}
if (!body.anneeFiscale || typeof body.anneeFiscale !== 'number') {
  throw new Error('anneeFiscale must be a number');
}

return [{ json: {
  tenantId: body.tenantId,
  anneeFiscale: body.anneeFiscale
} }];

// Build DAS2 declaration structure
const beneficiaries = $input.all()[0].json;
let totalMontant = 0;

const beneficiariesList = beneficiaries.map(b => {
  const montant = parseFloat(b.montant_honoraires || 0);
  totalMontant += montant;
  return {
    siret: b.siret,
    nom: b.nom,
    adresse: b.adresse,
    montant: montant
  };
});

const das2Declaration = {
  version: '2.0',
  annee_fiscale: $node["02. Parser"].json.anneeFiscale,
  nombre_beneficiaires: beneficiariesList.length,
  montant_total: totalMontant,
  beneficiaires: beneficiariesList
};

return {
  declaration: das2Declaration,
  beneficiaires: beneficiariesList,
  nombre_beneficiaires: beneficiariesList.length,
  montant_total: totalMontant
};

return {
  success: true,
  message: 'DAS2 declaration generated successfully',
  data: $node["07. Save Declaration"].json
};
